Here's how to save/restore draft text using MAUI's lifecycle events and `Preferences`:

**In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();

        // Subscribe to lifecycle events
        App.Current.Windows[0].Resumed += OnResumed;
        App.Current.Windows[0].Stopped += OnStopped;
    }

    private void OnStopped(object sender, EventArgs e)
    {
        // Save draft when app goes to background
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void OnResumed(object sender, EventArgs e)
    {
        // Restore draft when app returns
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();
        // Also restore on first load
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        // Unsubscribe to avoid leaks
        App.Current.Windows[0].Resumed -= OnResumed;
        App.Current.Windows[0].Stopped -= OnStopped;
    }

    public void ClearDraft()
    {
        // Call this after the user explicitly saves
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

- **`Window.Stopped`** fires when the app is backgrounded — save here.
- **`Window.Resumed`** fires when the app returns to foreground.
- **`Preferences`** is ideal for small text; for large content, use `SecureStorage` or a file via `FileSystem.AppDataDirectory`.
- Unsubscribe from events in `OnDisappearing` to prevent memory leaks.
- Call `ClearDraft()` after the user intentionally saves their note.
